#!/usr/bin/env python3
from pathlib import Path
import base64

ROOT = Path.cwd()

required = [
    "package.json",
    "app",
    "lib",
    "public",
]
for rel in required:
    if not (ROOT / rel).exists():
        raise FileNotFoundError(f"No encuentro {rel}. Ejecuta este script desde la raíz del proyecto mundial-porra-2026.")

# 1) Iconos recortados a sangre: quita el margen blanco externo que hacía que se vieran como miniatura.
icons = {
    "public/icon-192.png": "",
    "public/icon-512.png": "",
    "public/apple-touch-icon.png": "",
    "public/favicon-32.png": "",
}

for rel, data in icons.items():
    path = ROOT / rel
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_bytes(base64.b64decode(data))

# 2) Cache real de resultados: evita pedir football-data en cada navegación y acelera mucho la app.
(ROOT / "lib/footballData.ts").write_text('import matchesJson from "@/data/matches.json";\nimport type { Match, MatchResult } from "@/lib/types";\n\nconst API_URL = "https://api.football-data.org/v4/competitions/WC/matches";\nconst SEASON = "2026";\n\ntype FootballDataMatch = {\n  id: number;\n  utcDate: string;\n  status: string;\n  matchday?: number;\n  group?: string | null;\n  homeTeam: {\n    name: string;\n    shortName?: string;\n    tla?: string;\n  };\n  awayTeam: {\n    name: string;\n    shortName?: string;\n    tla?: string;\n  };\n  score: {\n    fullTime: {\n      home: number | null;\n      away: number | null;\n    };\n    halfTime?: {\n      home: number | null;\n      away: number | null;\n    };\n  };\n};\n\ntype FootballDataResponse = {\n  matches?: FootballDataMatch[];\n  message?: string;\n  errorCode?: number;\n};\n\nexport type ApiResultsPayload = {\n  results: Record<string, MatchResult>;\n  updatedAt: string;\n  source: "football-data";\n  error?: string;\n  matchedFixtures: number;\n  rawMatches: number;\n};\n\nconst matches = matchesJson as Match[];\n\nlet memoryCache: { payload: ApiResultsPayload; expiresAt: number } | null = null;\nconst CACHE_MS = 60_000;\n\nfunction normalize(value?: string | null): string {\n  return (value ?? "")\n    .normalize("NFD")\n    .replace(/\\p{Diacritic}/gu, "")\n    .replace(/&/g, "and")\n    .replace(/[^a-zA-Z0-9]+/g, " ")\n    .trim()\n    .toLowerCase();\n}\n\nconst TEAM_ALIASES: Record<string, string[]> = {\n  "México": ["Mexico", "MEX"],\n  "Sudáfrica": ["South Africa", "RSA"],\n  "Corea del Sur": ["South Korea", "Korea Republic", "KoreaRepublic", "KOR"],\n  "República Checa": ["Czech Republic", "Czechia", "CZE"],\n  "Canadá": ["Canada", "CAN"],\n  "Bosnia y Herzegovina": ["Bosnia and Herzegovina", "Bosnia-Herzegovina", "Bosnia-H.", "Bosnia", "BIH"],\n  "Estados Unidos": ["United States", "USA", "United States of America"],\n  "Paraguay": ["Paraguay", "PAR"],\n  "Catar": ["Qatar", "QAT"],\n  "Suiza": ["Switzerland", "SUI"],\n  "Brasil": ["Brazil", "BRA"],\n  "Marruecos": ["Morocco", "MAR"],\n  "Haití": ["Haiti", "HAI"],\n  "Escocia": ["Scotland", "SCO"],\n  "Australia": ["Australia", "AUS"],\n  "Turquía": ["Turkey", "Türkiye", "Turkiye", "TUR"],\n  "Alemania": ["Germany", "GER"],\n  "Curazao": ["Curacao", "Curaçao", "CUW"],\n  "Países Bajos": ["Netherlands", "Holland", "NED"],\n  "Japón": ["Japan", "JPN"],\n  "Costa de Marfil": ["Ivory Coast", "Cote d\'Ivoire", "Côte d\'Ivoire", "CIV"],\n  "Ecuador": ["Ecuador", "ECU"],\n  "Suecia": ["Sweden", "SWE"],\n  "Túnez": ["Tunisia", "TUN"],\n  "España": ["Spain", "ESP"],\n  "Cabo Verde": ["Cape Verde", "Cabo Verde", "CPV"],\n  "Bélgica": ["Belgium", "BEL"],\n  "Egipto": ["Egypt", "EGY"],\n  "Arabia Saudí": ["Saudi Arabia", "KSA"],\n  "Uruguay": ["Uruguay", "URU"],\n  "Irán": ["Iran", "IRN"],\n  "Nueva Zelanda": ["New Zealand", "NZL"],\n  "Francia": ["France", "FRA"],\n  "Senegal": ["Senegal", "SEN"],\n  "Irak": ["Iraq", "IRQ"],\n  "Noruega": ["Norway", "NOR"],\n  "Argentina": ["Argentina", "ARG"],\n  "Argelia": ["Algeria", "ALG"],\n  "Austria": ["Austria", "AUT"],\n  "Jordania": ["Jordan", "JOR"],\n  "Portugal": ["Portugal", "POR"],\n  "RD Congo": ["DR Congo", "Congo DR", "Congo Democratic Republic", "Democratic Republic of the Congo", "COD"],\n  "Inglaterra": ["England", "ENG"],\n  "Croacia": ["Croatia", "CRO"],\n  "Ghana": ["Ghana", "GHA"],\n  "Panamá": ["Panama", "PAN"],\n  "Uzbekistán": ["Uzbekistan", "UZB"],\n  "Colombia": ["Colombia", "COL"]\n};\n\nfunction aliasesFor(team: string): string[] {\n  return [team, ...(TEAM_ALIASES[team] ?? [])].map(normalize);\n}\n\nfunction apiTeamNames(team: FootballDataMatch["homeTeam"]): string[] {\n  return [team.name, team.shortName, team.tla].filter(Boolean).map((value) => normalize(value));\n}\n\nfunction sameDate(apiDateTime: string, matchDate?: string): boolean {\n  if (!matchDate) return true;\n  return apiDateTime.slice(0, 10) === matchDate;\n}\n\nfunction matchStatus(status: string): MatchResult["status"] {\n  if (["FINISHED", "AWARDED"].includes(status)) return "FINISHED";\n  if (["IN_PLAY", "PAUSED"].includes(status)) return "LIVE";\n  return "SCHEDULED";\n}\n\nfunction intersects(a: string[], b: string[]): boolean {\n  return a.some((item) => b.includes(item));\n}\n\nfunction matchFixture(match: Match, fixture: FootballDataMatch): "direct" | "reverse" | null {\n  const dateLooksClose = sameDate(fixture.utcDate, match.date);\n  const matchHomeAliases = aliasesFor(match.home);\n  const matchAwayAliases = aliasesFor(match.away);\n  const apiHomeAliases = apiTeamNames(fixture.homeTeam);\n  const apiAwayAliases = apiTeamNames(fixture.awayTeam);\n\n  const direct = intersects(matchHomeAliases, apiHomeAliases) && intersects(matchAwayAliases, apiAwayAliases);\n  const reverse = intersects(matchHomeAliases, apiAwayAliases) && intersects(matchAwayAliases, apiHomeAliases);\n\n  if (direct && dateLooksClose) return "direct";\n  if (reverse && dateLooksClose) return "reverse";\n  if (direct) return "direct";\n  if (reverse) return "reverse";\n\n  return null;\n}\n\nasync function fetchFootballDataResults(): Promise<ApiResultsPayload> {\n  const token = process.env.FOOTBALL_DATA_TOKEN;\n\n  if (!token) {\n    return {\n      results: {},\n      updatedAt: new Date().toISOString(),\n      source: "football-data",\n      matchedFixtures: 0,\n      rawMatches: 0,\n      error: "Falta FOOTBALL_DATA_TOKEN en las variables de entorno."\n    };\n  }\n\n  const url = `${API_URL}?season=${SEASON}`;\n\n  try {\n    const response = await fetch(url, {\n      headers: {\n        "X-Auth-Token": token\n      },\n      // Cachea la llamada en Vercel/Next durante 60s. Evita que cada navegación espere a la API externa.\n      next: {\n        revalidate: 60\n      }\n    });\n\n    const data = (await response.json()) as FootballDataResponse;\n\n    if (!response.ok) {\n      return {\n        results: {},\n        updatedAt: new Date().toISOString(),\n        source: "football-data",\n        matchedFixtures: 0,\n        rawMatches: data.matches?.length ?? 0,\n        error: data.message ?? `football-data respondió con HTTP ${response.status}.`\n      };\n    }\n\n    const apiMatches = data.matches ?? [];\n    const results: Record<string, MatchResult> = {};\n    let matchedFixtures = 0;\n\n    for (const match of matches) {\n      const found = apiMatches\n        .map((fixture) => ({ fixture, direction: matchFixture(match, fixture) }))\n        .find((item) => item.direction !== null);\n\n      if (!found) continue;\n\n      matchedFixtures += 1;\n\n      const { fixture, direction } = found;\n      const rawHome = direction === "direct" ? fixture.score.fullTime.home : fixture.score.fullTime.away;\n      const rawAway = direction === "direct" ? fixture.score.fullTime.away : fixture.score.fullTime.home;\n\n      if (typeof rawHome !== "number" || typeof rawAway !== "number") {\n        continue;\n      }\n\n      results[match.id] = {\n        homeGoals: rawHome,\n        awayGoals: rawAway,\n        status: matchStatus(fixture.status),\n        updatedAt: new Date().toISOString()\n      };\n    }\n\n    return {\n      results,\n      updatedAt: new Date().toISOString(),\n      source: "football-data",\n      matchedFixtures,\n      rawMatches: apiMatches.length\n    };\n  } catch (error) {\n    return {\n      results: {},\n      updatedAt: new Date().toISOString(),\n      source: "football-data",\n      matchedFixtures: 0,\n      rawMatches: 0,\n      error: error instanceof Error ? error.message : "Error desconocido consultando football-data."\n    };\n  }\n}\n\nexport async function getFootballDataResults(): Promise<ApiResultsPayload> {\n  const now = Date.now();\n\n  if (memoryCache && memoryCache.expiresAt > now) {\n    return memoryCache.payload;\n  }\n\n  const payload = await fetchFootballDataResults();\n  memoryCache = {\n    payload,\n    expiresAt: now + CACHE_MS\n  };\n\n  return payload;\n}\n', encoding="utf-8")

# 3) API route cacheable.
route_path = ROOT / "app/api/results/route.ts"
route_path.parent.mkdir(parents=True, exist_ok=True)
route_path.write_text('import { NextResponse } from "next/server";\nimport { getFootballDataResults } from "@/lib/footballData";\n\nexport const revalidate = 60;\n\nexport async function GET() {\n  const payload = await getFootballDataResults();\n\n  return NextResponse.json(payload, {\n    headers: {\n      "Cache-Control": "s-maxage=60, stale-while-revalidate=120"\n    }\n  });\n}\n', encoding="utf-8")

# 4) Quitar SSR forzado y usar ISR cada 60 segundos.
replacements = {'app/page.tsx': ('export const dynamic = "force-dynamic";', 'export const revalidate = 60;'), 'app/partidos/page.tsx': ('export const dynamic = "force-dynamic";', 'export const revalidate = 60;'), 'app/pronosticos/page.tsx': ('export const dynamic = "force-dynamic";', 'export const revalidate = 60;'), 'app/pronosticos/[player]/page.tsx': ('export const dynamic = "force-dynamic";', 'export const revalidate = 60;'), 'app/admin/page.tsx': ('export const dynamic = "force-dynamic";', 'export const revalidate = 60;')}
for rel, (old, new) in replacements.items():
    path = ROOT / rel
    if path.exists():
        content = path.read_text(encoding="utf-8")
        if old in content:
            content = content.replace(old, new)
        elif "export const revalidate = 60;" not in content:
            content = "export const revalidate = 60;\n\n" + content
        path.write_text(content, encoding="utf-8")

print("Aplicado fix: icono recortado a sangre y app acelerada con caché/ISR de 60s.")
print("Ejecuta: npm run build && git add . && git commit -m 'Fix app icon and improve performance' && git push && npx vercel --prod")
